import { describe, it, expect, beforeEach } from 'vitest';
import {
  WebhookAdapter,
  isValidWebhookUrl,
  formatWebhookPayload,
} from '../../src/adapters/webhook.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

describe('WebhookAdapter', () => {
  let adapter: WebhookAdapter;

  const samplePayload: NotificationPayload = {
    type: 'order_confirmation',
    recipient: 'alice@example.com',
    subject: 'Order Confirmation: order-0001',
    body: 'Your order has been placed.',
    channel: 'webhook',
    priority: 'normal',
  };

  beforeEach(() => {
    adapter = new WebhookAdapter({ stubMode: true, url: 'https://hooks.example.com/notify' });
  });

  // -------------------------------------------------------------------------
  // send() — core delivery
  // -------------------------------------------------------------------------

  describe('send', () => {
    it('should succeed in stub mode', async () => {
      const result = await adapter.send(samplePayload);

      expect(result.success).toBe(true);
      expect(result.channel).toBe('webhook');
    });

    it('should record deliveries in stub mode', async () => {
      await adapter.send(samplePayload);

      const deliveries = adapter.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.url).toBe('https://hooks.example.com/notify');
      expect(deliveries[0]?.payload.subject).toBe('Order Confirmation: order-0001');
    });

    it('should fail in non-stub mode (no real HTTP configured)', async () => {
      const productionAdapter = new WebhookAdapter({
        stubMode: false,
        url: 'https://hooks.example.com/notify',
      });
      const result = await productionAdapter.send(samplePayload);

      expect(result.success).toBe(false);
      expect(result.failureReason).toBeDefined();
    });

    it('should fail for invalid webhook URL', async () => {
      const badAdapter = new WebhookAdapter({
        stubMode: true,
        url: 'not-a-url',
      });
      const result = await badAdapter.send(samplePayload);

      expect(result.success).toBe(false);
      expect(result.failureReason).toContain('Invalid webhook URL');
    });

    it('should fail for empty webhook URL', async () => {
      const badAdapter = new WebhookAdapter({
        stubMode: true,
        url: '',
      });
      const result = await badAdapter.send(samplePayload);

      expect(result.success).toBe(false);
      expect(result.failureReason).toContain('Invalid webhook URL');
    });

    it('should include notification type in the delivery payload', async () => {
      await adapter.send(samplePayload);

      const deliveries = adapter.getDeliveries();
      expect(deliveries[0]?.payload.notificationType).toBe('order_confirmation');
      expect(deliveries[0]?.notificationType).toBe('order_confirmation');
    });

    it('should include recipient in the delivery payload', async () => {
      await adapter.send(samplePayload);

      const deliveries = adapter.getDeliveries();
      expect(deliveries[0]?.payload.recipient).toBe('alice@example.com');
    });

    it('should include subject in the delivery payload', async () => {
      await adapter.send(samplePayload);

      const deliveries = adapter.getDeliveries();
      expect(deliveries[0]?.payload.subject).toBe('Order Confirmation: order-0001');
    });

    it('should include body in the delivery payload', async () => {
      await adapter.send(samplePayload);

      const deliveries = adapter.getDeliveries();
      expect(deliveries[0]?.payload.body).toBe('Your order has been placed.');
    });

    it('should include priority in the delivery payload', async () => {
      await adapter.send(samplePayload);

      const deliveries = adapter.getDeliveries();
      expect(deliveries[0]?.payload.priority).toBe('normal');
    });

    it('should include channel as webhook in the delivery payload', async () => {
      await adapter.send(samplePayload);

      const deliveries = adapter.getDeliveries();
      expect(deliveries[0]?.payload.channel).toBe('webhook');
    });

    it('should include a timestamp in the delivery payload', async () => {
      await adapter.send(samplePayload);

      const deliveries = adapter.getDeliveries();
      expect(deliveries[0]?.payload.timestamp).toBeDefined();
      // Verify it's a valid ISO 8601 timestamp
      const parsed = new Date(deliveries[0]!.payload.timestamp);
      expect(parsed.getTime()).not.toBeNaN();
    });

    it('should record deliveredAt timestamp on deliveries', async () => {
      const before = new Date();
      await adapter.send(samplePayload);
      const after = new Date();

      const deliveries = adapter.getDeliveries();
      expect(deliveries[0]?.deliveredAt.getTime()).toBeGreaterThanOrEqual(
        before.getTime(),
      );
      expect(deliveries[0]?.deliveredAt.getTime()).toBeLessThanOrEqual(
        after.getTime(),
      );
    });

    it('should handle multiple sequential sends', async () => {
      await adapter.send(samplePayload);
      await adapter.send({
        ...samplePayload,
        recipient: 'bob@example.com',
        subject: 'Second Webhook',
      });

      const deliveries = adapter.getDeliveries();
      expect(deliveries).toHaveLength(2);
      expect(deliveries[0]?.payload.recipient).toBe('alice@example.com');
      expect(deliveries[1]?.payload.recipient).toBe('bob@example.com');
    });

    it('should propagate metadata from payload to webhook body', async () => {
      const payloadWithMeta: NotificationPayload = {
        ...samplePayload,
        metadata: { orderId: 'order-0001', trackingUrl: 'https://track.example.com' },
      };

      await adapter.send(payloadWithMeta);

      const deliveries = adapter.getDeliveries();
      expect(deliveries[0]?.payload.metadata).toEqual({
        orderId: 'order-0001',
        trackingUrl: 'https://track.example.com',
      });
    });

    it('should not throw even when send encounters an error', async () => {
      const productionAdapter = new WebhookAdapter({
        stubMode: false,
        url: 'https://hooks.example.com/notify',
        maxRetries: 1,
      });

      // Should not throw — returns failure result instead
      const result = await productionAdapter.send(samplePayload);
      expect(result.success).toBe(false);
      expect(result.failureReason).toBeDefined();
    });

    it('should handle all notification types', async () => {
      const types: NotificationPayload['type'][] = [
        'order_confirmation',
        'order_status_update',
        'welcome',
        'account_updated',
      ];

      for (const type of types) {
        const payload: NotificationPayload = {
          ...samplePayload,
          type,
        };
        const result = await adapter.send(payload);
        expect(result.success).toBe(true);
      }

      expect(adapter.getDeliveries()).toHaveLength(4);
    });

    it('should handle payloads without metadata', async () => {
      const noMetaPayload: NotificationPayload = {
        type: 'welcome',
        recipient: 'bob@example.com',
        subject: 'Welcome!',
        body: 'Welcome to the app.',
        channel: 'webhook',
        priority: 'normal',
      };

      const result = await adapter.send(noMetaPayload);

      expect(result.success).toBe(true);
      const deliveries = adapter.getDeliveries();
      expect(deliveries[0]?.payload.metadata).toBeUndefined();
    });
  });

  // -------------------------------------------------------------------------
  // Configuration
  // -------------------------------------------------------------------------

  describe('configuration', () => {
    it('should use default config when none provided', () => {
      const defaultAdapter = new WebhookAdapter();
      const config = defaultAdapter.getConfig();

      expect(config.url).toBe('https://localhost/webhook');
      expect(config.stubMode).toBe(true);
      expect(config.maxRetries).toBe(3);
      expect(config.timeoutMs).toBe(5000);
    });

    it('should merge custom config with defaults', () => {
      const customAdapter = new WebhookAdapter({
        url: 'https://custom.example.com/hook',
        timeoutMs: 10000,
      });
      const config = customAdapter.getConfig();

      expect(config.url).toBe('https://custom.example.com/hook');
      expect(config.timeoutMs).toBe(10000);
      expect(config.stubMode).toBe(true); // default preserved
      expect(config.maxRetries).toBe(3); // default preserved
    });

    it('should include maxRetries in default config', () => {
      const config = adapter.getConfig();
      expect(config.maxRetries).toBe(3);
    });

    it('should allow custom secret', () => {
      const customAdapter = new WebhookAdapter({ secret: 'my-secret-key' });
      const config = customAdapter.getConfig();
      expect(config.secret).toBe('my-secret-key');
    });

    it('should return a defensive copy of config', () => {
      const config1 = adapter.getConfig();
      const config2 = adapter.getConfig();
      expect(config1).toEqual(config2);
      expect(config1).not.toBe(config2);
    });
  });

  // -------------------------------------------------------------------------
  // Channel Property
  // -------------------------------------------------------------------------

  describe('channel property', () => {
    it('should report webhook as its channel', () => {
      expect(adapter.channel).toBe('webhook');
    });
  });

  // -------------------------------------------------------------------------
  // clearDeliveries
  // -------------------------------------------------------------------------

  describe('clearDeliveries', () => {
    it('should clear delivery records', async () => {
      await adapter.send(samplePayload);
      expect(adapter.getDeliveries()).toHaveLength(1);

      adapter.clearDeliveries();
      expect(adapter.getDeliveries()).toHaveLength(0);
    });
  });

  // -------------------------------------------------------------------------
  // Payload Formatting
  // -------------------------------------------------------------------------

  describe('payload formatting', () => {
    it('should format order_confirmation payload correctly', () => {
      const formatted = adapter.formatPayload(samplePayload);

      expect(formatted.notificationType).toBe('order_confirmation');
      expect(formatted.recipient).toBe('alice@example.com');
      expect(formatted.subject).toBe('Order Confirmation: order-0001');
      expect(formatted.body).toBe('Your order has been placed.');
      expect(formatted.channel).toBe('webhook');
      expect(formatted.priority).toBe('normal');
      expect(formatted.timestamp).toBeDefined();
    });

    it('should format order_status_update payload', () => {
      const statusPayload: NotificationPayload = {
        type: 'order_status_update',
        recipient: 'alice@example.com',
        subject: 'Order Update: order-0001',
        body: 'Your order status has changed from pending to shipped.',
        channel: 'webhook',
        priority: 'high',
      };

      const formatted = adapter.formatPayload(statusPayload);

      expect(formatted.notificationType).toBe('order_status_update');
      expect(formatted.priority).toBe('high');
